case class QueryRequest(query: String, maxRows: Int = 1000, timeoutSeconds: Int = 300)
case class QueryResponse(success: Boolean, data: Option[Array[Map[String, Any]]], error: Option[String], rowCount: Int)

class SecureQueryExecutor(spark: SparkSession) {
  
  private val allowedTables = Set(
    "sales_data",
    "customer_data", 
    "product_catalog",
    "transactions",
    "user_analytics"
  )
  
  private val maxRowsLimit = 10000
  private val maxTimeoutSeconds = 600
  
  def executeQuery(request: QueryRequest): QueryResponse = {
    try {
      val sanitizedQuery = request.query.trim
      
      if (sanitizedQuery.isEmpty) {
        return QueryResponse(false, None, Some("Query cannot be empty"), 0)
      }
      
      val validationResult = validateQuery(sanitizedQuery)
      if (!validationResult.isValid) {
        return QueryResponse(false, None, Some(s"Query validation failed: ${validationResult.reason}"), 0)
      }
      
      val effectiveMaxRows = Math.min(request.maxRows, maxRowsLimit)
      val effectiveTimeout = Math.min(request.timeoutSeconds, maxTimeoutSeconds)
      
      val limitedQuery = addLimitIfNeeded(sanitizedQuery, effectiveMaxRows)
      
      val resultTry = Try {
        spark.sparkContext.setJobGroup(
          s"user-query-${System.currentTimeMillis()}", 
          limitedQuery,
          interruptOnCancel = true
        )
        
        val future = scala.concurrent.Future {
          spark.sql(limitedQuery)
        }(scala.concurrent.ExecutionContext.global)
        
        val df = scala.concurrent.Await.result(future, scala.concurrent.duration.Duration(effectiveTimeout, TimeUnit.SECONDS))
        df
      }
      
      resultTry match {
        case Success(df) =>
          val rows = df.collect().map { row =>
            row.schema.fieldNames.map { fieldName =>
              fieldName -> (if (row.isNullAt(row.fieldIndex(fieldName))) null else row.get(row.fieldIndex(fieldName)))
            }.toMap
          }
          QueryResponse(true, Some(rows), None, rows.length)
          
        case Failure(e: java.util.concurrent.TimeoutException) =>
          spark.sparkContext.cancelJobGroup(s"user-query-${System.currentTimeMillis()}")
          QueryResponse(false, None, Some("Query execution timeout"), 0)
          
        case Failure(e: ParseException) =>
          QueryResponse(false, None, Some(s"SQL syntax error: ${e.getMessage}"), 0)
          
        case Failure(e) =>
          QueryResponse(false, None, Some(s"Query execution error: ${sanitizeErrorMessage(e.getMessage)}"), 0)
      }
      
    } catch {
      case e: Exception =>
        QueryResponse(false, None, Some(s"Unexpected error: ${sanitizeErrorMessage(e.getMessage)}"), 0)
    }
  }
  
  private def validateQuery(query: String): ValidationResult = {
    val upperQuery = query.toUpperCase
    
    val dangerousKeywords = List(
      "DROP", "DELETE", "TRUNCATE", "INSERT", "UPDATE", 
      "CREATE", "ALTER", "GRANT", "REVOKE", "MERGE",
      "LOAD", "EXPORT", "IMPORT", "COPY"
    )
    
    for (keyword <- dangerousKeywords) {
      if (upperQuery.matches(s".*\\b$keyword\\b.*")) {
        return ValidationResult(false, s"Forbidden operation: $keyword")
      }
    }
    
    if (upperQuery.contains("--") || upperQuery.contains("/*") || upperQuery.contains("*/")) {
      return ValidationResult(false, "Comments are not allowed in queries")
    }
    
    if (upperQuery.contains(";") && upperQuery.indexOf(";") < upperQuery.length - 1) {
      return ValidationResult(false, "Multiple statements are not allowed")
    }
    
    if (!upperQuery.trim.startsWith("SELECT") && !upperQuery.trim.startsWith("WITH")) {
      return ValidationResult(false, "Only SELECT and WITH queries are allowed")
    }
    
    try {
      val logicalPlan = spark.sessionState.sqlParser.parsePlan(query)
      
      if (!isReadOnlyPlan(logicalPlan)) {
        return ValidationResult(false, "Query contains non-read operations")
      }
      
      val referencedTables = extractTableNames(logicalPlan)
      val unauthorizedTables = referencedTables.filterNot(allowedTables.contains)
      
      if (unauthorizedTables.nonEmpty) {
        return ValidationResult(false, s"Access denied to tables: ${unauthorizedTables.mkString(", ")}")
      }
      
    } catch {
      case e: ParseException =>
        return ValidationResult(false, s"Invalid SQL syntax: ${e.getMessage}")
      case e: Exception =>
        return ValidationResult(false, s"Query parsing error: ${sanitizeErrorMessage(e.getMessage)}")
    }
    
    ValidationResult(true, "")
  }
  
  private def isReadOnlyPlan(plan: LogicalPlan): Boolean = {
    plan match {
      case _: Command => false
      case _: InsertIntoStatement => false
      case _ =>
        plan.children.forall(isReadOnlyPlan)
    }
  }
  
  private def extractTableNames(plan: LogicalPlan): Set[String] = {
    plan.collect {
      case UnresolvedRelation(tableIdentifier, _, _) =>
        tableIdentifier.table
    }.toSet
  }
  
  private def addLimitIfNeeded(query: String, maxRows: Int): String = {
    val upperQuery = query.toUpperCase.trim
    
    if (upperQuery.matches(".*\\bLIMIT\\s+\\d+.*")) {
      query
    } else {
      s"SELECT * FROM ($query) AS limited_query LIMIT $maxRows"
    }
  }
  
  private def sanitizeErrorMessage(message: String): String = {
    if (message == null) return "Unknown error"
    
    message
      .replaceAll("(?i)password[=:]\\s*\\S+", "password=***")
      .replaceAll("(?i)token[=:]\\s*\\S+", "token=***")
      .replaceAll("(?i)secret[=:]\\s*\\S+", "secret=***")
      .take(500)
  }
}

case class ValidationResult(isValid: Boolean, reason: String)

