class QueryAPIHandler(executor: SecureQueryExecutor) {
  
  def handleQueryRequest(queryString: String, maxRows: Int = 1000, timeoutSeconds: Int = 300): QueryResponse = {
    val request = QueryRequest(queryString, maxRows, timeoutSeconds)
    executor.executeQuery(request)
  }
  
  def handleBatchQueries(queries: List[QueryRequest]): List[QueryResponse] = {
    queries.map(executor.executeQuery)
  }
}